<?php
declare(strict_types=1);require dirname(__DIR__).'/app/core/Env.php';\App\Core\Env::load(dirname(__DIR__).'/.env');spl_autoload_register(function(string $class):void{$prefix='App\\';if(!str_starts_with($class,$prefix))return;$relative=substr($class,strlen($prefix));$parts=explode('\\',$relative);$parts[0]=strtolower($parts[0]);$file=dirname(__DIR__).'/app/'.implode('/',$parts).'.php';if(is_file($file))require_once $file;});$composer=dirname(__DIR__).'/vendor/autoload.php';if(is_file($composer))require_once $composer;use App\Core\Database;use App\Core\Env;use App\Services\EmailService;$pdo=Database::connection();$pdo->exec("INSERT INTO certification_renewals(employee_certification_id,status,requested_by,assigned_to,target_date,notes) SELECT c.id,'requested',NULL,c.user_id,c.expires_date,'Automatically created for expiring certification' FROM employee_certifications c WHERE c.status='active' AND c.expires_date BETWEEN CURDATE() AND DATE_ADD(CURDATE(),INTERVAL 60 DAY) AND NOT EXISTS(SELECT 1 FROM certification_renewals r WHERE r.employee_certification_id=c.id AND r.status IN('requested','in_progress','submitted'))");$mail=new EmailService();if(!$mail->configured())exit(0);$rows=$pdo->query("SELECT r.id,r.target_date,c.certification_name,u.email,u.name FROM certification_renewals r JOIN employee_certifications c ON c.id=r.employee_certification_id JOIN users u ON u.id=r.assigned_to WHERE r.status IN('requested','in_progress') AND u.email IS NOT NULL AND r.updated_at<DATE_SUB(NOW(),INTERVAL 7 DAY)")->fetchAll();$app=rtrim((string)Env::get('APP_URL',''),'/');foreach($rows as $r){try{$mail->sendMail($r['email'],'Certification renewal required: '.$r['certification_name'],'<p>'.htmlspecialchars($r['name']).',</p><p>Please renew '.htmlspecialchars($r['certification_name']).' by '.htmlspecialchars((string)$r['target_date']).'.</p><p><a href="'.$app.'/portal/certifications">Open certifications</a></p>');$pdo->prepare('UPDATE certification_renewals SET updated_at=NOW() WHERE id=?')->execute([$r['id']]);}catch(Throwable $e){fwrite(STDERR,$e->getMessage()."\n");}}
